#!/usr/bin/env bash
# Generated by scripts/generate-games.mjs — registers every ABC Kids game
# with the control-plane registry (ADR-054/ADR-055). Each game is multi-
# capability (ADR-056): three routes map state to a capability in the main
# slot — abc.play.<game> -> PlayGame, abc.show.<game> -> ShowCover,
# abc.info.<game> -> GetGameInfo. The registration does NOT pin
# moduleFederation.component, so the resolved capability per route drives
# which component the LayoutManager mounts.
set -euo pipefail
REGISTRY=${REGISTRY:-http://localhost:4000}

curl -fsS -X POST "$REGISTRY/mfes" -H "Content-Type: application/json" -d '{"registration":{"name":"abc-kids-flappy","version":"1.0.0","type":"remote","baseUrl":"http://localhost:3001","capabilities":["load","render"],"contentType":"module-federation","remoteEntryUrl":"http://localhost:3001/remoteEntry.js","moduleFederation":{"scope":"abc_kids_flappy","module":"./App"}},"routes":[{"when":{"stateKey":"abc.play.flappy"},"resolve":{"capability":"PlayGame","props":{"slot":"main"}}},{"when":{"stateKey":"abc.show.flappy"},"resolve":{"capability":"ShowCover","props":{"slot":"info"}}},{"when":{"stateKey":"abc.info.flappy"},"resolve":{"capability":"GetGameInfo","props":{"slot":"info"}}}]}' && echo " registered abc-kids-flappy (PlayGame/ShowCover/GetGameInfo)"
