curl -fsS -X POST "$REGISTRY/mfes" -H "Content-Type: application/json" -d '{"registration":{"name":"abc-kids-shape-sorter","version":"1.0.0","type":"remote","baseUrl":"http://localhost:3007","capabilities":["load","render"],"contentType":"module-federation","remoteEntryUrl":"http://localhost:3007/remoteEntry.js","moduleFederation":{"scope":"abc_kids_shape_sorter","module":"./App"}},"routes":[{"when":{"stateKey":"abc.play.shape-sorter"},"resolve":{"capability":"PlayGame","props":{"slot":"main"}}},{"when":{"stateKey":"abc.show.shape-sorter"},"resolve":{"capability":"ShowCover","props":{"slot":"info"}}},{"when":{"stateKey":"abc.info.shape-sorter"},"resolve":{"capability":"GetGameInfo","props":{"slot":"info"}}}]}' && echo " registered abc-kids-shape-sorter (PlayGame/ShowCover/GetGameInfo)"
