curl -fsS -X POST "$REGISTRY/mfes" -H "Content-Type: application/json" -d '{"registration":{"name":"abc-kids-animal-sounds","version":"1.0.0","type":"remote","baseUrl":"http://localhost:3009","capabilities":["load","render"],"contentType":"module-federation","remoteEntryUrl":"http://localhost:3009/remoteEntry.js","moduleFederation":{"scope":"abc_kids_animal_sounds","module":"./App"}},"routes":[{"when":{"stateKey":"abc.play.animal-sounds"},"resolve":{"capability":"PlayGame","props":{"slot":"main"}}},{"when":{"stateKey":"abc.show.animal-sounds"},"resolve":{"capability":"ShowCover","props":{"slot":"info"}}},{"when":{"stateKey":"abc.info.animal-sounds"},"resolve":{"capability":"GetGameInfo","props":{"slot":"info"}}}]}' && echo " registered abc-kids-animal-sounds (PlayGame/ShowCover/GetGameInfo)"
