curl -fsS -X POST "$REGISTRY/mfes" -H "Content-Type: application/json" -d '{"registration":{"name":"abc-kids-rocket-math","version":"1.0.0","type":"remote","baseUrl":"http://localhost:3011","capabilities":["load","render"],"contentType":"module-federation","remoteEntryUrl":"http://localhost:3011/remoteEntry.js","moduleFederation":{"scope":"abc_kids_rocket_math","module":"./App"}},"routes":[{"when":{"stateKey":"abc.play.rocket-math"},"resolve":{"capability":"PlayGame","props":{"slot":"main"}}},{"when":{"stateKey":"abc.show.rocket-math"},"resolve":{"capability":"ShowCover","props":{"slot":"info"}}},{"when":{"stateKey":"abc.info.rocket-math"},"resolve":{"capability":"GetGameInfo","props":{"slot":"info"}}}]}' && echo " registered abc-kids-rocket-math (PlayGame/ShowCover/GetGameInfo)"
