# Home / launcher MFE — root rule returns the full game catalog (ADR-058).
curl -fsS -X POST "$REGISTRY/mfes" -H "Content-Type: application/json" -d '{"registration":{"name":"abc-kids-home","version":"1.0.0","type":"remote","baseUrl":"http://localhost:3015","capabilities":["load","render"],"contentType":"module-federation","remoteEntryUrl":"http://localhost:3015/remoteEntry.js","moduleFederation":{"scope":"abc_kids_home","module":"./App"}},"routes":[{"when":{"stateKey":"abc.root"},"resolve":{"capability":"GameMenu","props":{"slot":"root","games":[{"id":"flappy","title":"Flappy","emoji":"🐤","color":"#0277bd"},{"id":"hockey","title":"Hockey","emoji":"🏒","color":"#37474f"},{"id":"counting-stars","title":"Counting Stars","emoji":"⭐","color":"#1a237e"},{"id":"letter-pop","title":"Letter Pop","emoji":"🎈","color":"#b71c1c"},{"id":"shape-sorter","title":"Shape Sorter","emoji":"🔷","color":"#004d40"},{"id":"color-mixer","title":"Color Mixer","emoji":"🎨","color":"#4a148c"},{"id":"animal-sounds","title":"Animal Sounds","emoji":"🐮","color":"#33691e"},{"id":"memory-match","title":"Memory Match","emoji":"🃏","color":"#880e4f"},{"id":"rocket-math","title":"Rocket Math","emoji":"🚀","color":"#0d47a1"},{"id":"word-builder","title":"Word Builder","emoji":"🔤","color":"#e65100"},{"id":"rhythm-tap","title":"Rhythm Tap","emoji":"🥁","color":"#263238"},{"id":"maze-runner","title":"Maze Runner","emoji":"🌀","color":"#1b5e20"}]}}}]}' && echo " registered abc-kids-home (GameMenu — root rule returns 12 games)"

